+        // First flush
+        buf.push(make_snap(1, 1000, 10, 1700000000));
+        let c1 = store.flush_buffer(&buf).unwrap();
+        assert_eq!(c1, 1);
+
+        // Second flush with more data
+        buf.push(make_snap(1, 2000, 20, 1700000030));
