+        let dbg_0 = format!("{:?}", store_0);
+        assert!(dbg_0.contains("0"), "0 days should be 0 hours, got: {}", dbg_0);
+
+        let store_365 = TelemetryStore::open_in_memory(365).unwrap();
+        let dbg_365 = format!("{:?}", store_365);
